var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"제 4 방어 포대, 수도 외곽지대\\n용병 조직 「위험한 녀석들」\\n─ 자크 산하 반군 생존자, 시설 점거 중","JPN":"第4防御砲台、首都外郭地帯\\n傭兵組織「危ない奴ら」\\n――ジャック傘下の反乱軍生存者、施設占拠中","ENG":"Defense Turret 4, capital’s outer region\\nThe Mercenary organization [Dangerous Bastards]\\n─ Rebel survivors under Jacques, occupying the facility","TWN":"第4防禦砲台，首都郊外\\n傭兵組織「危險分子」\\n─ 札克勢力的餘黨，佔領設施中","THA":"ป้อมปืนป้องกัน 4 เขตรอบนอกเมืองหลวง\\nองค์กรทหารรับจ้าง [เดนชนคนอันตราย]\\nกบฏใต้บังคับบัญชาของฌักส์ที่ยังรอดชีวิตกันอยู่ กำลังเข้ายึดอาคาร","VTN":"Tháp pháo Phòng thủ 4, khu vực bên ngoài của thủ đô\\nTổ chức lính đánh thuê [Những tên khốn nguy hiểm]\\n ─ Những người sống sót sau cuộc nổi dậy dưới quyền của Jacques, chiếm đóng cơ sở","SCN":"第4防御炮台，首都外围地区。\\n佣兵组织【危险的家伙们】\\n——扎克手下叛军幸存者，占领设施中","DEU":"Verteidigungseinheit 4, Außenregion der Hauptstadt\\nSöldner [Die Gefährlichen]\\n─ Überlebende Rebellen unter Jacques, Einrichtung besetzen","FRA":"Tourelle de défense n°4, environs de la capitale\\nOrganisation de mercenaires «\xA0Danger ambulant\xA0»\\n─ Anciens hommes de Jacques ayant pris le contrôle du bâtiment"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>4번 포대, 정기 교신 시간이다. 응답하라.</color>","JPN":"<color=#ffd34c>第4番砲台、定期交信の時間だ。応答せよ。</color>","ENG":"<color=#ffd34c>Defense Turret 4, it’s time to report. Do you copy.</color>","TWN":"<color=#ffd34c>4號砲台，定期通訊時間，請回答。</color>"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"아. 4번 포대. 교신 확인했다. 현 시각 확인 암호는……. 4……. 7…….","JPN":"ああ。第4番砲台。交信を確認した。現時刻の確認暗号は……4……7……","ENG":"Ahem. This is Defense Turret 4. Copy that. Verification password is 4... 7...","TWN":"蛤，4號砲台，確認通訊，密碼是……4……7……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"하……. 항복한다……. 사, 살려…….","JPN":"こ……降参だ……た、助け……","ENG":"I... I surrender... Please, spare...","TWN":"我……我投降……別…別殺…"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"실력도 마음가짐도 어설프다더니, 몽타뉴 님 말씀대로군요.","JPN":"実力も、心がけも中途半端と聞きましたが、モンターニュ様の言うとおりですね。","ENG":"You are lacking in both skills and spirit, as Montagne said.","TWN":"就跟蒙塔妮說的一樣，能力跟意志力都很糟糕。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"죽이려면 한 발로 확실하게 죽이세요. 고통만 길어집니다.","JPN":"殺すなら一発で確実にやりなさい。苦痛が長くなるだけです。","ENG":"If you intend to kill someone, it is better to kill them in one shot. You only prolong their suffering this way.","TWN":"要開槍就好好開，否則只是歹戲拖棚！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤, 헤헤……. 미안해, 칼잡이 나리. 이게, 약을 안 먹으면 손이 덜덜 떨려서.","JPN":"へ、へへ……ごめんよ、剣士の旦那。薬飲まねえと手がブルブル震えてさ。","ENG":"He he... Sorry, my hands shake when I haven’t taken any drug.","TWN":"嘿嘿嘿……不好意思，拿刀的大姊，因為我沒吃藥手會抖。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"그래도 정부군 놈들 전부 억 소리도 못 내게 해치우다니……","JPN":"でも政府軍の奴らをみんな声も出せねえうちにやっつけるなんて……","ENG":"Still, I can’t believe you got rid of all those government soldiers so easily...","TWN":"不過你三兩下就解決掉那些政府軍……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"역시 저격수 나리 친구 분들 실력은 굉장하구만.","JPN":"やっぱスナイパーの旦那のお仲間の実力はすげえな。","ENG":"That sniper’s friends really are that talented.","TWN":"狙擊手大姊的朋友果然厲害！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"……친구라고 하던가요?","JPN":"……仲間と紹介しましたか？","ENG":"…She called me friend?\\n\\n","TWN":"……你說朋友？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"엉? 아니야?","JPN":"あ？　違うのか？","ENG":"Huh? You aren’t?","TWN":"嗯？不是嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"아뇨. 같은 전쟁을 겪은 전우이니 친구라고 해도 이상할 것 없죠.","JPN":"いいえ。同じ戦争を経験した戦友ですので、仲間でもおかしくはありません。","ENG":"Hmm. Well, we’re comrades that have been through war together, I guess it isn’t a stretch to call us friends.","TWN":"沒事，畢竟是一起在戰場上出生入死的戰友，說是朋友也不為過。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"백업되어 있던 운영체계를 복구했습니다. 이제 에스타크도 제 위력을 발휘할 거예요. ","JPN":"バックアップされていたシステムを復旧しました。これでエスタークも元の威力を発揮できるはずです。 ","ENG":"The backup operating system has been restored. Estaque is now under our control. ","TWN":"備份的操作模式已復原，艾斯塔克終於可以發揮該有的威力。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"관리국 수송기를 격추시킨 다음에는……. 마음껏 쏴도 돼요.","JPN":"管理局の輸送機を撃墜した後には……思う存分撃ってもいいです。","ENG":"We’ll shoot down the Administration transport and then... You can shoot as much as your heart desires.","TWN":"等擊落管理局運輸機後……你就可以盡情掃射。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"흐, 흐헤헤헤! 신난다!","JPN":"ふ、ふへへへ！　やった！","ENG":"Hee hee! I’m excited!","TWN":"嘿嘿嘿！爽！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};